import api from './api';

export const userService = {
  createUser: async (user) => (await api.post('/api/users', user)).data,
  getAllUsers: async () => (await api.get('/api/users')).data,
  getUserById: async (id) => (await api.get(`/api/users/${id}`)).data,
  updateUser: async (id, user) => (await api.put(`/api/users/${id}`, user)).data,
  deleteUser: async (id) => (await api.delete(`/api/users/${id}`)).data,
  searchByEmail: async (email) => (await api.get(`/api/users/search/email/${email}`)).data,
  searchByName: async (name) => (await api.get(`/api/users/search/name/${name}`)).data,
};
